     1→import { Logger } from '@nestjs/common';
     2→import { algoliasearch } from 'algoliasearch';
     3→
     4→import { getEnv } from '@utils/get-env-variable.util';
     5→
     6→import {
     7→	ALG_API_KEY,
     8→	ALG_APP_ID,
     9→	ALG_INDEX_NAME,
    10→	CI_BASE_URL,
    11→} from '@constants/env-variables.constant';
    12→
    13→import { AlgoliaRelatedProductHit } from '@interfaces/algolia-hits.interface';
    14→import {
    15→	IMMSProductItem,
    16→	IMMSRelatedProductsPayload,
    17→} from '@interfaces/mms-related-products.interface';
    18→
    19→// npx ts-node -r dotenv/config -r tsconfig-paths/register ./src/scripts/mms-to-algolia-update.script.ts
    20→
    21→const logger = new Logger('mms-to-algolia-update');
    22→
    23→const algAppId = getEnv<string>({ key: ALG_APP_ID });
    24→const algApiKey = getEnv<string>({ key: ALG_API_KEY });
    25→const algIndexName = getEnv<string>({ key: ALG_INDEX_NAME });
    26→const mmsBaseUrl = getEnv<string>({ key: CI_BASE_URL });
    27→
    28→const client = algoliasearch(algAppId, algApiKey);
    29→
    30→const BATCH_SIZE = 1000; // Number of records to process in each batch
    31→const MAX_CONCURRENT_REQUESTS = 10; // Maximum number of concurrent API requests
    32→
    33→function extractProductNames(products: IMMSProductItem[]): string[] {
    34→	return products.filter((product) => product.name).map((product) => product.name);
    35→}
    36→async function processBatch(products: AlgoliaRelatedProductHit[]): Promise<void> {
    37→	logger.log(`Processing batch of ${products.length} products`);
    38→
    39→	// Process products in chunks to limit concurrent requests
    40→	for (let i = 0; i < products.length; i += MAX_CONCURRENT_REQUESTS) {
    41→		const chunk = products.slice(i, i + MAX_CONCURRENT_REQUESTS);
    42→		const chunkPromises = chunk.map(async (product) => {
    43→			const productId = product.objectID;
    44→			try {
    45→				logger.log(`Processing product ID: ${productId}`);
    46→
    47→				const mmsUrl = `${mmsBaseUrl}/products/styles/${productId}/related_styles.json?PK=${productId}`;
    48→
    49→				const mmsReq = await fetch(mmsUrl);
    50→				const data = (await mmsReq.json()) as IMMSRelatedProductsPayload | null;
    51→				if (!data) {
    52→					logger.warn(`No data found in MMS response for productId: ${productId}`);
    53→					return null;
    54→				}
    55→
    56→				const { alternatives } = data;
    57→
    58→				await client.saveObjects({
    59→					indexName: algIndexName,
    60→					objects: [{ ...product, mms_alternatives: extractProductNames(alternatives) }],
    61→				});
    62→
    63→				return productId;
    64→			} catch (error) {
    65→				logger.error(`Error processing product ID ${productId}:`, error);
    66→				return null;
    67→			}
    68→		});
    69→
    70→		const results = await Promise.all(chunkPromises);
    71→		const successCount = results.filter(Boolean).length;
    72→
    73→		logger.log(
    74→			`Completed chunk: ${successCount} of ${chunk.length} products updated successfully.`,
    75→		);
    76→	}
    77→}
    78→
    79→// Main function to process updates
    80→void (async () => {
    81→	logger.log('Starting update for all products in Algolia index with MMS alternatives.');
    82→
    83→	let page = 0;
    84→	let totalProcessed = 0;
    85→	let hasMorePages = true;
    86→
    87→	while (hasMorePages) {
    88→		try {
    89→			logger.log(`Fetching batch page ${page}...`);
    90→
    91→			const browse = await client.browse({
    92→				indexName: algIndexName,
    93→				browseParams: {
    94→					query: '',
    95→					hitsPerPage: BATCH_SIZE,
    96→					page,
    97→				},
    98→			});
    99→
   100→			if (browse.hits.length === 0) {
   101→				logger.log('No more products to process');
   102→				hasMorePages = false;
   103→				break;
   104→			}
   105→
   106→			await processBatch(browse.hits as AlgoliaRelatedProductHit[]);
   107→
   108→			totalProcessed += browse.hits.length;
   109→
   110→			logger.log(`Progress: Processed ${totalProcessed} products so far`);
   111→
   112→			page++;
   113→		} catch (error) {
   114→			logger.error(`Error processing batch at page ${page}:`, error);
   115→			hasMorePages = false;
   116→		}
   117→	}
   118→
   119→	logger.log(`Update process completed. Total products processed: ${totalProcessed}`);
   120→})();
